hooks.command:
python3 -c "
import json, sys
try:
    d = json.load(sys.stdin)
    fp = d.get('tool_input', {}).get('file_path', '')
    if fp.endswith(('VERSION','CHANGELOG.md')):
        print(json.dumps({'continue': True, 'systemMessage': '⚠ '+fp+' 已修改。如果是版本发布，请记得运行 tools/git/release.sh finish 并打标签。'}))
    else:
        print(json.dumps({'continue': True}))
except: print(json.dumps({'continue': True}))
"
